 955	    public WebClient createInsecureWebClient(String baseUrl) {
 956	        if (webClientCache.get(baseUrl) != null) {
 957	            return webClientCache.get(baseUrl);
 958	        }
 959	        HttpClient httpClient;
 960	        if (baseUrl.startsWith("https")) {
 961	            try {
 962	                // create insecure SSL context
 963	                SslContext sslContext = SslContextBuilder
 964	                        .forClient()
 965	                        .trustManager(InsecureTrustManagerFactory.INSTANCE)
 966	                        .build();
 967	
 968	                // create HttpClient with insecure SSL context
 969	                httpClient = HttpClient.create(connectionProvider)
 970	                        .secure(spec -> spec.sslContext(sslContext));
 971	            } catch (SSLException e) {
 972	                throw new RuntimeException(e);
 973	            }
 974	        } else {
 975	            // plain HTTP, create HttpClient normally
 976	            httpClient = HttpClient.create(connectionProvider);
 977	        }
 978	
 979	        // build WebClient with the created HttpClient
 980	        WebClient webClient = WebClient.builder()
 981	                .clientConnector(new ReactorClientHttpConnector(httpClient))
 982	                .baseUrl(baseUrl)
 983	                .build();
 984	        webClientCache.put(baseUrl, webClient);
 985	        return webClient;
 986	    }
